module RefModule (CLK, RST, EN, Q);
input CLK, RST, EN;
output reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin
    if (RST) begin
        Q <= 8'b11111111;
    end
    else if (EN) begin
        Q <= Q - 1;
    end
end

endmodule
